SELECT CHM.SEMESTRE FROM CALC_HORA_AULA_MEDIA AS CHM JOIN SERVIDOR AS S ON S.PK_SIAPE = CHM.SIAPE WHERE CHM.ANO = 2020 AND LOWER(CHM.SIGLA_CAMPUS) = LOWER('inh') AND LOWER(S.CONTRATO) = LOWER('efetivos') AND LOWER(S.AREA_INGRESSO) LIKE LOWER('%ciencia e tecnologia de alimentos%') GROUP BY CHM.SEMESTRE HAVING COUNT(DISTINCT S.PK_SIAPE) = 7 ORDER BY CHM.SEMESTRE